  coaching_execution = '{"movement_description":"Straight plank line, pull shoulder blades back and down, drive elbows behind body, chest to handles, controlled lower to full arm extension.","setup":["Set rings or straps around waist-to-chest height.","Athlete holds handles and walks feet forward.","Body forms a straight plank line.","Arms start straight with ribs and pelvis stacked.","Confirm anchor is secure and pain-free range for youth."],"execution_steps":["Pull shoulder blades slightly back and down.","Drive elbows behind the body.","Pull chest toward handles.","Pause briefly at top.","Lower with control until arms are straight.","Maintain body line throughout and rest fully between sets."],"breathing_cues":["Inhale on descent — exhale through the pull without losing brace."],"coach_cues":["Body like a plank.","Chest to rings.","Elbows drive back.","Squeeze your back.","Lower slow."],"athlete_cues":["Straight body.","Pull chest.","Squeeze back.","Control down."],"common_faults":["Hips sag.","Athlete curls with arms instead of rowing with back.","Shoulders roll forward at top.","Head reaches toward handles.","Body angle is too hard.","Rings drift unevenly."],"stop_signs":["Shoulder pain.","Elbow pain.","Grip failure before back work.","Cannot maintain body line.","Rings or straps are not anchored safely."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Inverted Row","Assisted Pull-Up","Rope Climb Foot-Lock Pull / Towel Pull","Scapular Pull-Up"],"pairs_well_after":["Band / Cable Row","Dead Hang / Active Hang","Scapular Retraction Drill"],"good_for_sessions":["capacity_upper_body","pull_capacity","strength_development"],"avoid_before":["Pull-ups if row body-line control is poor","Rope climbs if grip or scapular control is weak"],"avoid_after":[],"do_not_use_when":["Unsafe anchor","Shoulder pain with rowing","Cannot maintain plank line","Grip fails immediately"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["TRX and ring row progressions for athletic populations","Scalable bodyweight row teaching cues"],"internal_notes":["Validator should confirm ring row body line before inverted row or assisted pull-up."]}'::jsonb,
  updated_at = now()
WHERE slug = 'ring-row-trx-row';

