UPDATE coaching.exercise_regimen_rule r SET
  can_be_daily = FALSE,
  weekly_max_frequency = CASE WHEN FALSE THEN 7 ELSE r.weekly_max_frequency END
FROM coaching.exercise e
WHERE r.exercise_id = e.id AND e.slug = 'rope-climb-foot-lock-pull-towel-pull';

-- Refresh weighted taxonomy tags for upper-body pull, hang & grip Capacity cards
DELETE FROM coaching.exercise_tag t
USING coaching.exercise e
WHERE t.exercise_id = e.id
  AND e.slug IN ('ring-row-trx-row', 'inverted-row', 'one-arm-dumbbell-row', 'band-cable-row', 'assisted-pull-up', 'eccentric-pull-up-chin-up-negative', 'pull-up-chin-up', 'scapular-pull-up', 'dead-hang-active-hang', 'rope-climb-foot-lock-pull-towel-pull')
  AND t.facet_type IN ('tenet', 'methodology', 'physiology', 'pattern', 'equipment', 'body_region');

