FROM (VALUES
  ('ring-row-trx-row', 'Higher rings or straps, more upright body angle with coach at side.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('inverted-row', 'High bar row with bent knees or ring/TRX row — not full inverted row until earned.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('one-arm-dumbbell-row', 'Light DB row with support or band row only with coach.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('band-cable-row', 'Light band row, 2–3 sets of 8–12 with full rest.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('assisted-pull-up', 'Ring row, bar hang, or box-assisted pull-up with feet support only.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('eccentric-pull-up-chin-up-negative', 'Do not use full negatives; use ring rows or assisted holds only.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('pull-up-chin-up', 'Ring row, assisted pull-up, or active hang only — not strict pull-up until earned.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('scapular-pull-up', 'Feet-assisted active hang scapular pulls with coach.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('dead-hang-active-hang', 'Feet-assisted hang, 5–10 seconds with coach.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('rope-climb-foot-lock-pull-towel-pull', 'Seated foot-lock practice, towel grip holds, or rope lean-back rows only.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.')
) AS v(slug, guidance, gender_notes)
