-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('ring-row-trx-row', 'Ring and TRX rows scale difficulty by body angle while training lats, rhomboids, traps, rear delts, arms, grip, and trunk stability without full bodyweight vertical pull demand. They build horizontal pulling reserve relevant to bars, rings, ninja, and rope progressions.', 'Belongs in horizontal_pull_strength (441) — foundational Capacity horizontal pull before inverted row and vertical pull progressions.', 'Primary entry in horizontal_pull_strength after Output; default pulling regression before inverted rows, assisted pull-ups, and harder hanging work.', 'Upper-body pull, hang and grip Capacity builds pulling reserve with controlled load and full rest — not high-rep Fitness circuits or arm-burning grip endurance work. Do not use as high-rep conditioning, allow hip sag every rep, or steepen angle before plank line and scapular control are clean.', 'Regress to more upright body angle or band row; progress to lower angle or feet-elevated row only when ribs stay stacked and elbows track. Hypermobility athletes need active scapular control — no passive shoulder hang.'),
  ('inverted-row', 'The inverted row strengthens horizontal pulling while requiring a rigid plank-like body position under a fixed bar. Bar height and foot position scale difficulty while building pulling force capacity relevant to bars, gymnastics, and ninja work.', 'Belongs in horizontal_pull_strength (441) — fixed-bar horizontal Capacity pull after ring/TRX row competency, before assisted vertical pull.', 'horizontal_pull_strength after ring/TRX row competency; before assisted vertical pull when rigid body line under a fixed bar is established.', 'Upper-body pull, hang and grip Capacity builds pulling reserve with controlled load and full rest — not high-rep Fitness circuits or arm-burning grip endurance work. Do not use unstable bar setup, allow hip sag, shorten range every rep, or prescribe before ring row control is earned.', 'Regress to high bar with bent knees or ring/TRX row; progress to feet-elevated or tempo row only when chest reaches bar with clean body line. Cue active shoulder engagement — no passive hanging.'),
  ('one-arm-dumbbell-row', 'The one-arm row builds unilateral pulling strength while bench support reduces trunk demand enough to focus on the back. It develops lat and upper-back force capacity and left-right balance without hanging or vertical pull prerequisites.', 'Belongs in single_arm_pull_strength (442) — unilateral Capacity pull complement to horizontal rows, parallel to vertical pull progression track.', 'single_arm_pull_strength alongside horizontal rows; unilateral pull when hanging or vertical progressions are too difficult or grip-limited.', 'Upper-body pull, hang and grip Capacity builds pulling reserve with controlled load and full rest — not high-rep Fitness circuits or arm-burning grip endurance work. Do not yank weight with momentum, allow torso rotation, or prescribe heavy load before trunk stabilization is clean.', 'Regress to lighter load or band row; progress load only when elbow tracks and torso stays square. Avoid shoulder dumping at bottom — cue active scapular control.'),
  ('band-cable-row', 'Band and cable rows allow adjustable resistance with a stable setup, building pulling strength and scapular capacity for athletes who need scalable loading without bodyweight row demand. Ideal for broad class programming and return-to-training progressions.', 'Belongs in row_strength (443) — scalable Capacity row accessory after or alongside ring and inverted rows.', 'row_strength as the most adjustable row option for broad classes, return-to-training athletes, and accessory pulling volume alongside ring and inverted rows.', 'Upper-body pull, hang and grip Capacity builds pulling reserve with controlled load and full rest — not high-rep Fitness circuits or arm-burning grip endurance work. Do not use unsafe anchor, lean back to pull, let band snap back, or stack high reps with short rest.', 'Regress to lighter band or seated cable row; progress resistance only when posture and scapular control stay clean. Cue active scapular control — avoid end-range shoulder dumping.'),
  ('assisted-pull-up', 'Assisted pull-ups reduce load so the athlete can practice vertical pulling with better range and control. They build lat, upper-back, biceps, grip, and trunk tension relevant to bars, rings, ninja, and rope work while progressing toward strict pull-ups.', 'Belongs in vertical_pull_progression (444) — first vertical Capacity pull after horizontal row competency, before eccentric and strict pull-up work.', 'vertical_pull_progression after horizontal row competency; before eccentric negatives and strict pull-ups when full-range controlled vertical pull is not yet available.', 'Upper-body pull, hang and grip Capacity builds pulling reserve with controlled load and full rest — not high-rep Fitness circuits or arm-burning grip endurance work. Do not allow kicking, band bounce, incomplete lowering, or prescribe before horizontal row control is earned.', 'Regress to ring row or band row; increase assistance before reducing it only when every rep stays strict. Cue active shoulder control — avoid passive painful hang at bottom.'),
  ('eccentric-pull-up-chin-up-negative', 'Eccentric pull-ups emphasize controlled lowering where the athlete often tolerates more load than concentric lifting. They build vertical pull tissue capacity and deceleration-relevant strength when dosed conservatively with full rest — distinct from kipping or high-rep pull work.', 'Belongs in vertical_pull_eccentric (445) — eccentric Capacity vertical pull after assisted pull-up competency, before strict pull-up work.', 'vertical_pull_eccentric after assisted pull-up competency; before strict pull-ups when controlled eccentric lowering from top position is established.', 'Upper-body pull, hang and grip Capacity builds pulling reserve with controlled load and full rest — not high-rep Fitness circuits or arm-burning grip endurance work. Do not drop quickly from top, prescribe high volume, stack before ninja grip skill, or use before assisted pull-up control is earned.', 'Regress to band-assisted negative or partial range; shorten eccentric duration before adding load. Keep volume lower than standard pull-up — no passive shoulder dump at bottom.'),
  ('pull-up-chin-up', 'Pull-ups and chin-ups load lats, upper back, biceps, forearms, grip, and trunk control in a multi-joint vertical pull directly relevant to bars, rings, ninja, rope climbs, and gymnastics. Capacity intent with strict reps and full rest builds tissue reserve without kipping Output demand.', 'Belongs in vertical_pull_strength (446) — primary strict Capacity vertical pull after assisted and eccentric progressions, before scapular, hang, and climb work.', 'vertical_pull_strength after assisted pull-up and eccentric competency; primary strict vertical pull before scapular accessory, hang, and climb progressions.', 'Upper-body pull, hang and grip Capacity builds pulling reserve with controlled load and full rest — not high-rep Fitness circuits or arm-burning grip endurance work. Do not kip, rep out with short rest, prescribe before assisted pull-up control, or use partial reps as Capacity work.', 'Regress to assisted pull-up or eccentric negative; progress to weighted or pause pull-up only when every strict rep stays clean. Maintain active shoulder control at bottom — no passive painful hang.'),
  ('scapular-pull-up', 'Scapular pull-ups train the first shoulder-blade action that supports controlled pull-ups and active hangs. They build scapular depression and retraction strength relevant to bars, rings, rope climbs, and ninja without elbow flexion.', 'Belongs in scapular_pull_strength (447) — straight-arm scapular Capacity pull after strict pull-up competency, before hang and climb progressions.', 'scapular_pull_strength after strict pull-up competency; scapular depression and pull-up initiation accessory before hang tolerance and climb work.', 'Upper-body pull, hang and grip Capacity builds pulling reserve with controlled load and full rest — not high-rep Fitness circuits or arm-burning grip endurance work. Do not bend elbows into a mini pull-up, allow swinging, or prescribe before pull-up or assisted pull competency when hang is painful.', 'Regress to feet-assisted active hang scapular pulls or band straight-arm pulldown; progress to rings or weighted active hang only when straight-arm control stays clean.'),
  ('dead-hang-active-hang', 'Hangs build grip endurance and shoulder tolerance; active hangs teach scapular control while suspended. They develop hang and grip reserve relevant to bars, rings, ninja, rope climbs, and gymnastics when progressed with short holds and full rest.', 'Belongs in hang_grip_capacity (448) — isometric Capacity hang after scapular pull competency, before climb-specific rope work.', 'hang_grip_capacity after scapular pull-up competency; scalable hang and grip exposure before rope climb and climb-specific work.', 'Upper-body pull, hang and grip Capacity builds pulling reserve with controlled load and full rest — not high-rep Fitness circuits or arm-burning grip endurance work. Do not hang to failure, jump up without safe step-down, allow painful passive shoulder dump, or prescribe before scapular control is established.', 'Regress to feet-assisted hang for 5–10 seconds; progress hold time before removing foot support. Prefer active hang for hypermobility — avoid uncontrolled passive shoulder dumping.'),
  ('rope-climb-foot-lock-pull-towel-pull', 'Rope climbing capacity should not be arm-only. Foot-lock technique lets the athlete use legs while arms stabilize and pull. Towel pulls and low rope rows build grip and climbing strength before full climb height when dosed with supervision and safe descent.', 'Belongs in climb_grip_strength (449) — climbing-specific Capacity pull after hang and grip competency; end of pull cluster progression.', 'climb_grip_strength after hang and grip competency; bridge between rows, pull-ups, and hangs toward rope climbing with foot-lock mechanics first.', 'Upper-body pull, hang and grip Capacity builds pulling reserve with controlled load and full rest — not high-rep Fitness circuits or arm-burning grip endurance work. Do not climb arms-only before foot lock is secure, skip mat and supervision, or continue after grip failure when descent is unsafe.', 'Regress to seated foot-lock practice, towel row, or rope lean-back; progress to low rope pulls and climb attempts only when foot lock, grip, and descent control are established.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
