  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Upper-body pull / hang / grip Capacity cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'capacity_pull_readiness',
  NULL,
  'Pull / Hang / Grip Capacity without stealing skill safety',
  'Pulling and hanging Capacity needs intentional load, controlled reps, and full rest — not arm-burning circuits or grip-to-failure before bar/ninja work.',
  'Pull cluster: ring/TRX row, inverted row, one-arm DB row, band/cable row, assisted pull-up, eccentric pull-up, strict pull-up, scapular pull-up, dead/active hang, and rope foot-lock/towel pull.',
  'Pulling strength supports ninja, gymnastics, bars, rings, rope climbs, and grip endurance. Poor progression gates or grip fatigue before skill work raises injury risk and reduces movement quality.',
  'Progress rows → assisted vertical → eccentrics → pull-ups → scapular → hang → climb; regress on wrist/shoulder/elbow pain; keep eccentric and hang volume conservative before ninja/bar skill.',
  'Do not program kipping pull-ups as Capacity, use eccentrics before ring rows, hang to failure before ninja skill, or rope climbs without foot-lock competency and safe descent.'
)
